import{_ as t,o,c as e,a5 as r}from"./chunks/framework.B5tqjWbr.js";const g=JSON.parse('{"title":"学习记录 #0014：多级联调——PFC+DC-DC+逆变器协同","description":"","frontmatter":{"date":"2026-06-14T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"学习记录 #0014：多级联调——PFC+DC-DC+逆变器协同","tags":["power-electronics"],"status":"learning","summary":"**日期**：2026-06-13 **课程**：第14课 — 多级联调（Phase 2核心拓扑·最后一课） **状态**：进行中"},"headers":[],"relativePath":"content/power/archive/old-learning-records/0014-cascade-coordination.md","filePath":"content/power/archive/old-learning-records/0014-cascade-coordination.md","lastUpdated":null}'),n={name:"content/power/archive/old-learning-records/0014-cascade-coordination.md"};function i(s,a,l,c,d,h){return o(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="学习记录-0014-多级联调——pfc-dc-dc-逆变器协同" tabindex="-1">学习记录 #0014：多级联调——PFC+DC-DC+逆变器协同 <a class="header-anchor" href="#学习记录-0014-多级联调——pfc-dc-dc-逆变器协同" aria-label="Permalink to &quot;学习记录 #0014：多级联调——PFC+DC-DC+逆变器协同&quot;">​</a></h1><p><strong>日期</strong>：2026-06-13 <strong>课程</strong>：第14课 — 多级联调（Phase 2核心拓扑·最后一课） <strong>状态</strong>：进行中</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><ol><li><strong>级联架构</strong>：PFC→DC母线→{逆变器+DC-DC}，母线是公共节点</li><li><strong>Middlebrook判据</strong>：|Zout/Zin|&lt;1，前级输出阻抗必须远小于后级输入阻抗</li><li><strong>负输入阻抗</strong>：恒功率负载V↑I↓→dV/dI&lt;0→Zin&lt;0，导致级联不稳定</li><li><strong>4种稳定性改善</strong>：增大Cbus、提高PFC带宽、有源阻尼、母线电压前馈</li><li><strong>母线波动</strong>：单相PFC 100Hz纹波最严重，需4000μF电容</li><li><strong>启动时序</strong>：PFC→DC-DC→逆变器→旁路切换，绝对不能乱序</li><li><strong>3层保护</strong>：硬件(μs)→软件快速(10~100μs)→软件慢速(ms)</li><li><strong>逆变器短路处理</strong>：关逆变器+切旁路，PFC保持运行</li></ol><h2 id="phase-2-完成总结" tabindex="-1">Phase 2 完成总结 <a class="header-anchor" href="#phase-2-完成总结" aria-label="Permalink to &quot;Phase 2 完成总结&quot;">​</a></h2><ul><li>第7-14课，8节核心拓扑与控制课全部完成</li><li>掌握了PFC、逆变器、LLC、双向DC-DC、多级联调</li><li>下一阶段：Phase 3系统集成</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>进入第15课：后备式UPS完整软件设计（Phase 3系统集成）</p>',8)])])}const p=t(n,[["render",i]]);export{g as __pageData,p as default};
